resource "aws_security_group" "wide_open" {
  name        = "restricted-sg"
  description = "Allows only HTTPS inbound from a known office CIDR"

  ingress {
    description = "https from office"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["203.0.113.0/24"]
  }

  egress {
    description = "https outbound only"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
}
